local ipairs = ipairs
local LxProtoIds = LxProtoIds
local LxProtoHelper = LxProtoHelper

local LxBaseHandler = require("LApp.handler.LxBaseHandler")
---@class LxFriendHandler:LxBaseHandler
local LxFriendHandler = classX("LxFriendHandler", LxBaseHandler)

function LxFriendHandler:Initialize()
    LxBaseHandler.Initialize(self)
end

function LxFriendHandler:Dispose()
    LxBaseHandler.Dispose(self)
end

function LxFriendHandler:ClearHandler()
    self._chatMod = nil
    LxBaseHandler.ClearHandler(self)
end

function LxFriendHandler:InitOk()
end

-- 完成登录后
function LxFriendHandler:LoginOk()
    self:FriendDataReq()
end

-- 初始化协议
function LxFriendHandler:InitHandler()
    self:AddMsgHandler(LxProtoIds.FriendDataResp, self.OnFriendDataResp, self)
    self:AddMsgHandler(LxProtoIds.FriendshipResp, self.OnFriendshipResp, self)
    self:AddMsgHandler(LxProtoIds.FriendshipAuditResp, self.OnFriendshipAuditResp, self)
    self:AddMsgHandler(LxProtoIds.FriendRecommendResp, self.OnFriendRecommendResp, self)
    self:AddMsgHandler(LxProtoIds.FriendDeleteResp, self.OnFriendDeleteResp, self)
    self:AddMsgHandler(LxProtoIds.FriendGiftResp, self.OnFriendGiftResp, self)
    self:AddMsgHandler(LxProtoIds.FriendReceiveGiftResp, self.OnFriendReceiveGiftResp, self)
    self:AddMsgHandler(LxProtoIds.BlacklistOperateResp, self.OnBlacklistOperateResp, self)
    self:AddMsgHandler(LxProtoIds.FriendDataUpdateResp, self.OnFriendDataUpdateResp, self)
    self:AddMsgHandler(LxProtoIds.FriendTopOperateResp, self.OnFriendTopOperateResp, self)
end
function LxFriendHandler:FriendTopOperateReq(type,roleId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.FriendTopOperateReq)
    proto.type = type
    proto.roleId = roleId
    SendMessage(LxProtoIds.FriendTopOperateReq,proto)
end
function LxFriendHandler:OnFriendTopOperateResp(pb)
    local type = pb.type;
    local roleId = pb.roleId
    if(type == 0)then
        ShowSysMsg(I18nText(4857))
    else
        ShowSysMsg(I18nText(4858))
    end
end
-- 请求好友数据
function LxFriendHandler:FriendDataReq()
    local proto = LxProtoHelper.CreateProto(LxProtoIds.FriendDataReq)
    SendMessage(LxProtoIds.FriendDataReq, proto)
end

-- 请求好友数据 返回
function LxFriendHandler:OnFriendDataResp(pb)
    local LxFriendModule = ModuleCenter.Friend
    local list = {}
    for k, v in ipairs(pb.friends) do
        list[k] = v.roleInfo
        LxFriendModule:SetFriendStateMap(v)

        LxFriendModule:DeleteRecommend(v.roleInfo.roleId)
    end
    LxFriendModule:SetLoveNum(pb.sendGiftCount, pb.receiveGiftCount)
    LxFriendModule:SetFriendList(list)
    LxFriendModule:SetBlackList(pb.blacks)


    local list = {}
    local max = LxFriendModule:GetApplyListMax()
    for i = #pb.requests, 1, -1 do
        if max == 0 then
            break
        end
        table.insert(list, pb.requests[i])
        max = max - 1
    end
    LxFriendModule:SetApplyList(list)

    FireEvent(EventNames.FRIEND_BLACK_CHANGE)
    FireEvent(EventNames.FRIEND_RECOMMEND_RETURN)
    FireEvent(EventNames.FRIEND_APPLY_CHANGE)
    FireEvent(EventNames.FRIEND_LIST_CHANGE)
end

-- 好友请求
function LxFriendHandler:FriendshipReq(roleId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.FriendshipReq)
    proto.otherId = roleId
    SendMessage(LxProtoIds.FriendshipReq, proto)
end

-- 好友请求 返回
function LxFriendHandler:OnFriendshipResp(pb)
    -- 已发送好友请求
    ShowSysMsg(I18nText(4823))
end

-- 好友请求审核
function LxFriendHandler:FriendshipAuditReq(type, roleId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.FriendshipAuditReq)
    -- 1-单个同意,2-单个拒绝,3-一键同意,4-一键拒绝
    proto.type = type
    proto.otherId = roleId or 0
    SendMessage(LxProtoIds.FriendshipAuditReq, proto)
end

-- 好友请求审核 返回
function LxFriendHandler:OnFriendshipAuditResp(pb)
    if pb.type == 2 or pb.type == 4 then
        ShowSysMsg(I18nText(4824))
    else
        ShowSysMsg(I18nText(4825))
    end

    for _, roleId in ipairs(pb.removes) do
        ModuleCenter.Friend:DeleteApply(roleId)
    end
    FireEvent(EventNames.FRIEND_APPLY_CHANGE)
end

-- 好友推荐
function LxFriendHandler:FriendRecommendReq(strName)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.FriendRecommendReq)
    -- 搜索关键字,默认空返回系统推荐
    proto.param = strName or ""
    SendMessage(LxProtoIds.FriendRecommendReq, proto)
end

-- 好友推荐 返回
function LxFriendHandler:OnFriendRecommendResp(pb)
    local LxFriendModule = ModuleCenter.Friend
    LxFriendModule:SetRecommendList(pb.roleInfos)

    ModuleCenter.Friend:SaveChangeRecommedTime()
    FireEvent(EventNames.FRIEND_RECOMMEND_RETURN)
end

-- 删除好友
function LxFriendHandler:FriendDeleteReq(roleId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.FriendDeleteReq)
    proto.otherId = roleId
    SendMessage(LxProtoIds.FriendDeleteReq, proto)
end

-- 删除好友 返回
function LxFriendHandler:OnFriendDeleteResp(pb)
    ModuleCenter.Friend:DeleteFriend(pb.remove)
    FireEvent(EventNames.FRIEND_LIST_CHANGE)
end

