-- 黑名单操作
function LxFriendHandler:BlacklistOperateReq(type, roleId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.BlacklistOperateReq)
    -- 0-拉黑,1-取消拉黑
    proto.type = type
    proto.roleId = roleId or 0
    SendMessage(LxProtoIds.BlacklistOperateReq, proto)
end

-- 黑名单操作 返回
function LxFriendHandler:OnBlacklistOperateResp(pb)
    if pb:HasField("simpleInfo") then
        ModuleCenter.Friend:AddBlack(pb.simpleInfo)
        if ModuleCenter.Friend:IsMyFriend(pb.simpleInfo.roleId) then
            ModuleCenter.Friend:DeleteFriend(pb.simpleInfo.roleId)
            FireEvent(EventNames.FRIEND_LIST_CHANGE)
        end
    end
    if pb:HasField("remove") then
        ModuleCenter.Friend:DeleteBlack(pb.remove)
    end
    FireEvent(EventNames.FRIEND_BLACK_CHANGE)
end

-- 好友数据更新 返回
function LxFriendHandler:OnFriendDataUpdateResp(pb)
    local LxFriendModule = ModuleCenter.Friend

    local changeMap = {}
    for _, v in ipairs(pb.updateFriends) do
        local id = LxFriendModule:UpdateFriendAndBlackAndApply(v.roleInfo)
        if id == 1 then
            LxFriendModule:SetFriendStateMap(v)
        end
        changeMap[id] = true
    end
    for _, v in ipairs(pb.addFriends) do
        LxFriendModule:AddFriend(v.roleInfo)
        LxFriendModule:SetFriendStateMap(v)
        changeMap[1] = true
    end

    local send, receive =  LxFriendModule:GetLoveNum()
    if send ~= pb.sendGiftCount or receive ~= pb.receiveGiftCount then
        LxFriendModule:SetLoveNum(pb.sendGiftCount, pb.receiveGiftCount)
        changeMap[11] = true
    end

    for _, v in ipairs(pb.addRequests) do
        LxFriendModule:AddApply(v)
    end

    if #pb.addRequests > 0 then
        changeMap[3] = true
    end

    if changeMap[1] then
        LxFriendModule:SortFriendList()
    end
    if changeMap[2] then
        FireEvent(EventNames.FRIEND_BLACk_CHANGE)
    end
    if changeMap[3] then
        FireEvent(EventNames.FRIEND_APPLY_CHANGE)
    end
    if changeMap[1] or changeMap[11] then
        FireEvent(EventNames.FRIEND_LIST_CHANGE)
    end
end

return LxFriendHandler
